proof fn phi_1_entails_apply_closure_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
        p.satisfied_by(ex),
    ensures
        q.satisfied_by(ex),
{
    entails_apply::<int>(ex, p, q);
}

proof fn phi_2_temp_pred_equality_intensional_bridge(p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
        q.entails(p),
    ensures
        p == q,
{
    temp_pred_equality::<int>(p, q);
}

proof fn phi_3_entails_and_temp_closure_bridge(spec: TempPred<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        spec.entails(p),
        spec.entails(q),
    ensures
        spec.entails(p.and(q)),
{
    entails_and_temp::<int>(spec, p, q);
}

proof fn phi_4_mutual_entailment_derives_false_if_distinct(p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
        q.entails(p),
        p !== q,
    ensures
        false,
{
    temp_pred_equality::<int>(p, q);
}

proof fn phi_5_simplify_predicate_equality(p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
    ensures
        p == p.and(q),
{
    simplify_predicate::<int>(p, q);
}
